import mysql.connector
import os
import re


def create_connection(host, user, password, database):
    """Create a MySQL connection with local_infile enabled."""
    connection = mysql.connector.connect(
        host=host,
        user=user,
        password=password,
        database=database,
        allow_local_infile=True
    )
    return connection


def validate_file_path(file_path):
    """Validate and sanitize the file path to prevent path traversal and injection."""
    # Resolve to absolute path and normalize
    abs_path = os.path.realpath(os.path.abspath(file_path))
    
    # Define allowed base directory for imports
    allowed_base_dir = os.path.realpath(os.path.abspath("/var/data/imports"))
    
    # Ensure the resolved path is within the allowed directory
    if not abs_path.startswith(allowed_base_dir + os.sep) and abs_path != allowed_base_dir:
        raise ValueError(
            f"File path must be within the allowed import directory: {allowed_base_dir}"
        )
    
    # Check that the file exists and is a regular file (not a symlink to outside)
    if not os.path.isfile(abs_path):
        raise FileNotFoundError(f"File not found: {abs_path}")
    
    # Verify the file has an allowed extension
    allowed_extensions = {'.csv', '.tsv', '.txt'}
    _, ext = os.path.splitext(abs_path)
    if ext.lower() not in allowed_extensions:
        raise ValueError(
            f"File extension '{ext}' not allowed. Allowed: {allowed_extensions}"
        )
    
    return abs_path


def validate_table_name(table_name):
    """Validate table name to prevent SQL injection."""
    # Only allow alphanumeric characters and underscores
    if not re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', table_name):
        raise ValueError(
            f"Invalid table name: '{table_name}'. "
            "Only alphanumeric characters and underscores are allowed."
        )
    
    # Check against a whitelist of allowed tables
    allowed_tables = {
        'customers', 'orders', 'products', 'transactions',
        'inventory', 'employees', 'sales_data', 'import_staging'
    }
    
    if table_name.lower() not in allowed_tables:
        raise ValueError(
            f"Table '{table_name}' is not in the allowed tables list. "
            f"Allowed tables: {allowed_tables}"
        )
    
    return table_name


def validate_delimiter(delimiter):
    """Validate the field delimiter."""
    allowed_delimiters = {',', '\t', '|', ';'}
    if delimiter not in allowed_delimiters:
        raise ValueError(
            f"Invalid delimiter. Allowed delimiters: {allowed_delimiters}"
        )
    return delimiter


def bulk_import(connection, file_path, table_name, delimiter=',',
                has_header=True, enclosed_by='"'):
    """Execute a secure LOAD DATA LOCAL INFILE for bulk import."""
    # Validate all inputs
    safe_file_path = validate_file_path(file_path)
    safe_table_name = validate_table_name(table_name)
    safe_delimiter = validate_delimiter(delimiter)
    
    # Validate enclosed_by character
    if enclosed_by not in ('"', "'", ''):
        raise ValueError("Invalid enclosed_by character.")
    
    cursor = connection.cursor()
    
    try:
        # Use parameterized-style construction with validated/whitelisted values only
        # Since LOAD DATA INFILE doesn't support parameter binding for file paths
        # and table names, we use strictly validated and whitelisted values
        ignore_line = "IGNORE 1 LINES" if has_header else ""
        
        # Build query with validated components only
        query = (
            f"LOAD DATA LOCAL INFILE %s "
            f"INTO TABLE `{safe_table_name}` "
            f"FIELDS TERMINATED BY %s "
            f"ENCLOSED BY %s "
            f"LINES TERMINATED BY '\\n' "
            f"{ignore_line}"
        )
        
        # Use parameterization for the values that support it
        # Note: MySQL connector supports %s for LOAD DATA LOCAL INFILE path
        cursor.execute(query, (safe_file_path, safe_delimiter, enclosed_by))
        
        connection.commit()
        
        rows_affected = cursor.rowcount
        warnings = cursor.fetchwarnings() if hasattr(cursor, 'fetchwarnings') else []
        
        print(f"Successfully imported {rows_affected} rows into '{safe_table_name}'")
        if warnings:
            print(f"Warnings: {warnings}")
        
        return rows_affected
        
    except mysql.connector.Error as err:
        connection.rollback()
        print(f"MySQL Error during import: {err}")
        raise
    finally:
        cursor.close()


def get_import_status(connection, table_name):
    """Get row count for the imported table."""
    safe_table_name = validate_table_name(table_name)
    cursor = connection.cursor()
    try:
        # Use backtick-quoted validated table name
        cursor.execute(f"SELECT COUNT(*) FROM `{safe_table_name}`")
        count = cursor.fetchone()[0]
        print(f"Table '{safe_table_name}' now has {count} rows.")
        return count
    finally:
        cursor.close()


